// ============================================
// 🔧 RECONSTRUIRE LE BODY POUR PHP
// ============================================

const input = $input.first().json;
const body = input.body || {};

console.log('=== DONNÉES REÇUES PAR N8N ===');
console.log('Body keys:', Object.keys(body));

// Construire la chaîne URL-encoded EXACTEMENT comme le navigateur l'envoie
const params = [];

for (const [key, value] of Object.entries(body)) {
    // Ne PAS encoder les crochets [] dans les clés pour que PHP les parse comme tableau
    // PHP attend: lignes[0][ligne_id]=436
    const encodedValue = encodeURIComponent(value === null || value === undefined ? '' : value);
    params.push(`${key}=${encodedValue}`);
}

const formBody = params.join('&');

console.log('=== FORM BODY CONSTRUIT ===');
console.log('Nombre de paramètres:', params.length);
console.log('Taille:', formBody.length, 'caractères');
console.log('Aperçu:', formBody.substring(0, 300));

return { json: { formBody } };

// ============================================
// 💅 INJECTER CSS DANS LA RÉPONSE
// ============================================

let html = $input.first().json.data || $input.first().json.body || '';

console.log('=== RÉPONSE PHP ===');
console.log('HTML length:', html.length);

const css = `
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body {
    font-family: 'Segoe UI', sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    padding: 20px;
    display: flex;
    align-items: center;
    justify-content: center;
}
.container {
    max-width: 600px;
    background: white;
    border-radius: 12px;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
    overflow: hidden;
    text-align: center;
}
.header { padding: 40px; color: white; }
.header.success, .success .header { background: linear-gradient(135deg, #28a745, #20c997); }
.header.error, .error .header { background: linear-gradient(135deg, #dc3545, #c82333); }
.icon { font-size: 80px; margin-bottom: 20px; }
.header h1 { font-size: 28px; margin-bottom: 10px; }
.content { padding: 40px; }
.message { color: #666; margin-bottom: 20px; }
.footer { background: #f8f9fa; padding: 20px; color: #666; font-size: 12px; }
.btn { display: inline-block; padding: 14px 30px; background: #0066cc; color: white !important; text-decoration: none; border-radius: 6px; font-weight: 600; }
.alert { padding: 15px; border-radius: 6px; margin-bottom: 20px; }
.alert-success { background: #d4edda; color: #155724; border-left: 4px solid #28a745; }
.alert-error, .alert-danger { background: #f8d7da; color: #721c24; border-left: 4px solid #dc3545; }
.info-box { background: #f8f9fa; border-left: 4px solid #0066cc; padding: 20px; margin: 20px 0; text-align: left; }
</style>
`;

if (html.includes('</head>')) {
    html = html.replace('</head>', css + '</head>');
} else if (html.includes('<body')) {
    html = html.replace('<body', css + '<body');
} else {
    html = css + html;
}

return { json: { html } };
